head.script:
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {

};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    //소스
    if ($c.data.getMemInfo("userId") == "kh1472") //7W01
    {
        ed_wrkPlCd.setValue("7W01");
        ed_wrkPlNm.setValue("보랄대구창고");
        $c.gus.cfDisableObjects([ed_wrkPlCd, ed_wrkPlNm]);
    }

    let strCurDate = $c.date.getServerDateTime("yyyyMMdd"); //현재일자
    ds_condition.insertRow(0);
    ds_condition.setRowPosition(0);
    ds_condition.setCellData(0, "inQryCond", "0");
    ds_condition.setCellData(0, "ioIntendFmDt", strCurDate);
    ds_condition.setCellData(0, "ioIntendToDt", strCurDate);

    tac_tabControl1.activateTab(1);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await $c.gus.cfValidate([tbl_condition])) {
        return;
    }

    if (!scwin.f_BetweenCheck(ed_ioIntendFmDt.getValue().trim(), ed_ioIntendToDt.getValue().trim())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_057, new Array("입고일자To", "입고일자From"));
        ed_reqStDt.focus();
        return;
    }

    if (tac_tabControl1.getSelectedTabIndex() == 0) {
        $c.sbm.execute(sbm_retrieve2);
    } else {
        $c.sbm.execute(sbm_retrieve);
    }
};

//-------------------------------------------------------------------------
// 숫자 차이 체크
//-------------------------------------------------------------------------
scwin.f_BetweenCheck = function (str1, str2) {
    if ((str1 == "" && str2 != "") || (str1 != "" && str2 == "")) {
        return false;
    }
    if (parseInt(str2) - parseInt(str1) < 0) {
        return false;
    }
    return true;
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
